def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        modifier = 1.0
        penalty = 0.0
        extra = 0.0
        decay = 1.0
        complex_factor = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 8):
                penalty += ((ratio ** (2 * k + 1)) / (k ** 2 + 2)) * ((-1) ** k)
            for j in range(1, 5):
                decay *= (1 - 1 / (ratio + j + 1))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            priorities[i] = max(score * decay, 1e-8)
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                score += sign * (ratio ** x) / (x + 1)
            for y in range(1, 6):
                decay *= (1 - 1 / (y + ratio + 2))
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 6)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 4)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 20 if ratio < 2.5 else 12
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m + 5)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for n in range(1, 20):
                if n % 5 == 0:
                    temp_score -= (ratio ** n) / (n * 7)
                elif n % 4 == 0:
                    temp_score += (ratio ** n) / (n * 3)
                elif n % 3 == 0:
                    temp_score -= (ratio ** n) / (n * 5)
                else:
                    temp_score += (ratio ** n) / (n * 4)
            if ratio < 1.25:
                modifier = 30
            elif ratio < 1.6:
                modifier = 18
            else:
                modifier = 10
            score = abs(temp_score) * modifier
            if 1.85 < ratio < 1.95:
                extra_penalty = 0
                for s in range(1, 10):
                    extra_penalty += (ratio ** s) / (s + 2)
                score += extra_penalty * 2
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for w in range(1, 25):
                if w % 6 == 0:
                    temp_score += (ratio ** w) / (w * 2)
                elif w % 5 == 0:
                    temp_score -= (ratio ** w) / (w * 8)
                elif w % 4 == 0:
                    temp_score += (ratio ** w) / (w * 4)
                elif w % 3 == 0:
                    temp_score -= (ratio ** w) / (w * 6)
                else:
                    temp_score += (ratio ** w) / (w * 5)
            if ratio < 0.1:
                modifier = 40
            elif ratio < 0.3:
                modifier = 25
            elif ratio < 0.5:
                modifier = 17
            elif ratio < 0.7:
                modifier = 10
            else:
                modifier = 7
            score = abs(temp_score) * modifier
            if ratio > 0.9:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 2)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + (z ** 1.5) / (bins[i] + z))
            priorities[i] *= factor
            secondary_factor = 0.0
            for r in range(1, 5):
                secondary_factor += (item / (bins[i] + r)) ** 2 / (r + 1)
            priorities[i] += secondary_factor * 5
        elif bins[i] <= 0:
            priorities[i] = np.inf
    worst = np.nanmax(priorities[np.isfinite(priorities)]) if np.any(np.isfinite(priorities)) else 0
    if worst > 0:
        for i in range(len(priorities)):
            if priorities[i] != np.inf:
                priorities[i] = np.log1p(priorities[i]) / np.log1p(worst)
    return priorities
